import {
  BlockStack,
  Icon,
  Box,
  CalloutCard,
  Card,
  Text,
  Button,
  Grid,
  InlineStack,
  InlineGrid,
  Page,
  Banner,
  Popover,
  DatePicker,
} from "@shopify/polaris";
import {
  ChevronDownIcon,
  CheckIcon,
  LanguageIcon,
  GlobeAsiaIcon,
  CalendarIcon,
  EmailNewsletterIcon,
  ThemeEditIcon,
  GiftCardIcon,
  ChevronLeftIcon,
  ChevronRightIcon,
} from "@shopify/polaris-icons";
import { NavLink, useNavigate } from "react-router-dom";
import React, { useState, useEffect, lazy, Suspense } from "react";
import useEffectDashboard from "./useEffectDashboard";
import DatePicking from "../../components/DatePicking";
import { useTranslation } from "react-i18next";
const PricingTable = lazy(() => import("../../components/Pricing/PricingPage"));

const Dashboard = () => {
  console.log("dasboard");
  const { t, i18n } = useTranslation(["dashboard", "onboarding"]);
  const [selectedTime, setSelectedTime] = useState("all_time");
  const [selectedLng, setSelectedLng] = useState("en");
  const navigate = useNavigate();
  const { filterValue, setFilterValue } = useEffectDashboard();

  const formatDateToShortString = date => {
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    const year = date.getFullYear();
    return `${month}-${day}-${year}`;
  };

  const handleFilterDate = dates => {
    const formattedDateFrom = formatDateToShortString(new Date(dates.date_from));
    const formattedDateTo = formatDateToShortString(new Date(dates.date_to));

    setFilterValue(prev => ({
      ...prev,
      date_from: formattedDateFrom,
      date_to: formattedDateTo,
      date_range: dates.date_range,
    }));
  };

  return (
    <>
      <div className="dashboard-container">
        <div className="dashboard-wrap">
          <div className="dashboard-middle">
            <Card>
              <Box>
                <BlockStack gap={200}>
                  <DatePicking
                    key={selectedLng}
                    t={key => t(key, { ns: "translation" })}
                    filterValue={filterValue}
                    handleFilterDate={handleFilterDate}
                    haveIcon={true}
                    getPeriod={true}
                    haveInputField={true}
                    havePrimaryIcon={true}
                    activatorId="date-picker-activator"
                    disabled={false}
                  />
                </BlockStack>
              </Box>
            </Card>
          </div>
        </div>
      </div>
    </>
  );
};

export default Dashboard;
