import { useState, useRef, useEffect } from "react";
import {
    BlockStack,
    Box,
    DatePicker,
    Button,
    InlineGrid,
    InlineStack,
    OptionList,
    Popover,
    TextField,
    useBreakpoints,
    Icon,
    Select,
    Scrollable,
} from "@shopify/polaris";

import {
    CalendarIcon,
    ArrowRightIcon,
    ChevronDownIcon,
} from "@shopify/polaris-icons";

const DatePicking = ({
    t,
    filterValue,
    handleFilterDate,
    haveIcon,
    getPeriod,
    haveInputField = true,
    havePrimaryIcon = false,
    defaultLabel,
    activatorId,
    disabled
}) => {
    const { mdDown, lgUp } = useBreakpoints();
    const initDate = {
        date_from: filterValue.date_from,
        date_to: filterValue.date_to,
        date_range: filterValue.date_range
    };
    // console.log("Filter value:", filterValue);

    const shouldShowMultiMonth = lgUp;
    const allDate = new Date(new Date("1973-1-1").setHours(0, 0, 0, 0));
    const today = new Date(new Date().setHours(0, 0, 0, 0));
    const yesterday = new Date(
        new Date(new Date().setDate(today.getDate() - 1)).setHours(0, 0, 0, 0)
    );
    const ranges = [
        {
            title: t("filter_date.today", { ns: "translation" }),
            alias: "today",
            period: {
                since: today,
                until: today,
            },
        },
        {
            title: t("filter_date.yesterday", { ns: "translation" }),
            alias: "yesterday",
            period: {
                since: yesterday,
                until: yesterday,
            },
        },
        {
            title: t("filter_date.last_7_days", { ns: "translation" }),
            alias: "last_7_days",
            period: {
                since: new Date(
                    new Date(new Date().setDate(today.getDate() - 7)).setHours(
                        0,
                        0,
                        0,
                        0
                    )
                ),
                until: yesterday,
            },
        },
        {
            title: t("filter_date.last_30_days", { ns: "translation" }),
            alias: "last_30_days",
            period: {
                since: new Date(
                    new Date(new Date().setDate(today.getDate() - 30)).setHours(
                        0,
                        0,
                        0,
                        0
                    )
                ),
                until: today,
            },
        },
        {
        title: t("filter_date.last_60_days", { ns: "translation" }),
        alias: "last_60_days",
        period: {
            since: new Date(
                new Date(new Date().setDate(today.getDate() - 60)).setHours(0, 0, 0, 0)
            ),
            until: today,
            },
        },
        {
        title: t("filter_date.last_90_days", { ns: "translation" }),
        alias: "last_90_days",
        period: {
            since: new Date(
                new Date(new Date().setDate(today.getDate() - 90)).setHours(0, 0, 0, 0)
            ),
            until: today,
            },
        },
        {
            title: t("filter_date.last_year", { ns: "translation" }),
            alias: "last_365_days",
            period: {
                since: new Date(
                    new Date(
                        new Date().setDate(today.getDate() - 365)
                    ).setHours(0, 0, 0, 0)
                ),
                until: today,
            },
        },
        {
            title: t("filter_date.all_times", { ns: "translation" }),
            alias: "all_time",
            period: {
                since: allDate,
                until: today,
            },
        },
        {
            title: t("filter_date.custom_range", { ns: "translation" }),
            alias: "custom_range",
            period: {
                since: today,
                until: today,
            },
        },
    ];

    const [popoverActive, setPopoverActive] = useState(false);
    const [activeDateRange, setActiveDateRange] = useState(
        ranges.find(range => range.alias === "all_time")
    );

    const [inputValues, setInputValues] = useState({
        date_from: "",
        date_to: "",
        date_range: "",
    });

    const [{ month, year }, setDate] = useState({
        month: activeDateRange.period.since.getMonth(),
        year: activeDateRange.period.since.getFullYear(),
    });

    const formatDateToLongString = (date) => {
        return date.toLocaleDateString("en-US", {
            year: "numeric",
            month: "long",
            day: "numeric",
        });
    };
    const datePickerRef = useRef(null);
    const VALID_YYYY_MM_DD_DATE_REGEX = /^\d{4}-\d{1,2}-\d{1,2}/;

    const isDate = (date) => {
        return !isNaN(new Date(date).getDate());
    };

    const isValidYearMonthDayDateString = (date) => {
        return VALID_YYYY_MM_DD_DATE_REGEX.test(date) && isDate(date);
    };

    const isValidDate = (date) => {
        return date.length === 10 && isValidYearMonthDayDateString(date);
    };

    const parseYearMonthDayDateString = (input) => {
        const [year, month, day] = input.split("-");
        return new Date(Number(year), Number(month) - 1, Number(day));
    };

    const formatDateToYearMonthDayDateString = (date) => {
        const year = String(date.getFullYear());
        let month = String(date.getMonth() + 1);
        let day = String(date.getDate());
        if (month.length < 2) {
            month = String(month).padStart(2, "0");
        }
        if (day.length < 2) {
            day = String(day).padStart(2, "0");
        }
        return [year, month, day].join("-");
    };

    const formatDate = (date) => {
        return formatDateToYearMonthDayDateString(date);
    };

    const nodeContainsDescendant = (rootNode, descendant) => {
        if (rootNode === descendant) {
            return true;
        }
        let parent = descendant.parentNode;
        while (parent != null) {
            if (parent === rootNode) {
                return true;
            }
            parent = parent.parentNode;
        }
        return false;
    };

    const isNodeWithinPopover = (node) => {
        return datePickerRef?.current
            ? nodeContainsDescendant(datePickerRef.current, node)
            : false;
    };

    const handleStartInputValueChange = (value) => {
        setInputValues({ ...inputValues, date_from: value });
        if (isValidDate(value)) {
            const newSince = parseYearMonthDayDateString(value);
            setActiveDateRange((prevState) => {
                const newPeriod =
                    prevState.period && newSince <= prevState.period.until
                        ? { since: newSince, until: prevState.period.until }
                        : { since: newSince, until: newSince };
                return {
                    ...prevState,
                    period: newPeriod,
                };
            });
        }
    };

    const handleEndInputValueChange = (value) => {
        setInputValues({ ...inputValues, date_to: value });
        if (isValidDate(value)) {
            const newUntil = parseYearMonthDayDateString(value);
            setActiveDateRange((prevState) => {
                const newPeriod =
                    prevState.period && newUntil >= prevState.period.since
                        ? { since: prevState.period.since, until: newUntil }
                        : { since: newUntil, until: newUntil };
                return {
                    ...prevState,
                    period: newPeriod,
                };
            });
        }
    };

    const handleInputBlur = ({ relatedTarget }) => {
        const isRelatedTargetWithinPopover =
            relatedTarget != null && isNodeWithinPopover(relatedTarget);
        if (isRelatedTargetWithinPopover) {
            return;
        }
    };

    const handleMonthChange = (month, year) => {
        setDate({ month, year });
    };

    const handleCalendarChange = ({ start, end }) => {
        const newDateRange = ranges.find((range) => {
            return (
                range.period.since.valueOf() === start.valueOf() &&
                range.period.until.valueOf() === end.valueOf()
            );
        }) || {
            alias: "custom_range",
            title: "Custom",
            period: {
                since: start,
                until: end,
            },
        };
        setActiveDateRange(newDateRange);
    };

    const handleApplyDate = () => {
        handleFilterDate({...inputValues,date_range: activeDateRange.alias});
        setPopoverActive(false);
    };
    const cancel = () => {
        setPopoverActive(false);
        setInputValues(initDate);
        handleInitDate(initDate.date_from, initDate.date_to, initDate.date_range);
    };

    useEffect(() => {
        if (activeDateRange) {
            setInputValues({
                date_from: formatDateToLongString(activeDateRange.period.since),
                date_to: formatDateToLongString(activeDateRange.period.until),
                date_range: activeDateRange.alias
            });
            const monthDiff = (referenceDate, newDate) => {
                return (
                    newDate.month -
                    referenceDate.month +
                    12 * (referenceDate.year - newDate.year)
                );
            };
            const monthDifference = monthDiff(
                { year, month },
                {
                    year: activeDateRange.period.until.getFullYear(),
                    month: activeDateRange.period.until.getMonth(),
                }
            );
            if (monthDifference > 1 || monthDifference < 0) {
                setDate({
                    month: activeDateRange.period.until.getMonth(),
                    year: activeDateRange.period.until.getFullYear(),
                });
            }
        }
    }, [activeDateRange]);

    const buttonValue =
        activeDateRange.title === "Custom"
            ? formatDate(activeDateRange.period.since) +
              " - " +
              formatDate(activeDateRange.period.until)
            : defaultLabel &&
              activeDateRange.title ===
                  t("filter_date.all_times", { ns: "translation" })
            ? defaultLabel
            : activeDateRange.title;

    const handleInitDate = (from, to) => {
        if (from && to) {
            const newDateRange = ranges.find((range) => {
                return (
                    range.period.since.valueOf() ===
                        new Date(
                            new Date(from).setHours(0, 0, 0, 0)
                        ).valueOf() &&
                    range.period.until.valueOf() ===
                        new Date(new Date(to).setHours(0, 0, 0, 0)).valueOf()
                );
            }) || {
                alias: "custom_range",
                title: "Custom",
                period: {
                    since: new Date(new Date(from).setHours(0, 0, 0, 0)),
                    until: new Date(new Date(to).setHours(0, 0, 0, 0)),
                },
            };
            setActiveDateRange(newDateRange);
        } else {
            const newDateRange = {
                title: t("filter_date.all_times", { ns: "translation" }),
                alias: "all_time",
                period: {
                    since: allDate,
                    until: today,
                },
            };
            setActiveDateRange(newDateRange);
            let filterDate = newDateRange.period;
            console.log(activeDateRange.alias

            )
            if(getPeriod){
                filterDate["date_range"] = activeDateRange.alias
            }
            handleFilterDate(filterDate);
        }
    };
    useEffect(() => {
        handleInitDate(filterValue.date_from, filterValue.date_to, filterValue.date_range);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [filterValue.date_from, filterValue.date_to, filterValue.date_range]);

    return (
        <Popover
            active={popoverActive}
            autofocusTarget="none"
            preferredAlignment="left"
            preferredPosition="below"
            fluidContent
            sectioned={false}
            fullHeight
            activator={
                <Button
                    fullWidth
                    textAlign="left"
                    icon={haveIcon ? CalendarIcon : undefined}
                    onClick={() => setPopoverActive(!popoverActive)}
                    ariaExpanded={false}
                    id={activatorId ? activatorId: null}
                    disabled={disabled}
                >
                    <InlineStack
                        blockAlign="center"
                        wrap={false}
                        gap={100}
                        align="start"
                    >
                        <p className="date-custom--ranger">{buttonValue}</p>
                        {havePrimaryIcon && <Icon source={ChevronDownIcon} />}
                    </InlineStack>
                </Button>
            }
            onClose={() => setPopoverActive(false)}
        >
            <Box padding={400}>
                <Popover.Pane fixed>
                    <InlineGrid
                        columns={{
                            xs: "1fr",
                            mdDown: "1fr",
                            md: "max-content max-content",
                        }}
                        gap={0}
                        ref={datePickerRef}
                    >
                        <Box
                            maxWidth={mdDown ? "516px" : "212px"}
                            width={mdDown ? "100%" : "212px"}
                            padding={{ xs: 500, md: 0 }}
                            paddingBlockEnd={{ xs: 100, md: 0 }}
                            borderInlineEndWidth="0165"
                            borderColor="border"
                            borderBlockEndWidth="0165"
                        >
                            {mdDown ? (
                                <Select
                                    label="dateRangeLabel"
                                    labelHidden
                                    onChange={(value) => {
                                        const result = ranges.find(
                                            ({ title, alias }) =>
                                                title === value ||
                                                alias === value
                                        );
                                        setActiveDateRange(result);
                                    }}
                                    value={
                                        activeDateRange?.title ||
                                        activeDateRange?.alias ||
                                        ""
                                    }
                                    options={ranges.map(
                                        ({ alias, title }) => title || alias
                                    )}
                                />
                            ) : (
                                <Scrollable style={{ height: "334px" }}>
                                    <OptionList
                                        options={ranges.map((range) => ({
                                            value: range.alias,
                                            label: range.title,
                                        }))}
                                        selected={activeDateRange.alias}
                                        onChange={(value) => {
                                            setActiveDateRange(
                                                ranges.find(
                                                    (range) =>
                                                        range.alias === value[0]
                                                )
                                            );
                                        }}
                                    />
                                </Scrollable>
                            )}
                        </Box>
                        <Box
                            padding={{ xs: 500 }}
                            maxWidth={mdDown ? "320px" : "516px"}
                            borderBlockEndWidth="0165"
                            borderColor="border"
                        >
                            <BlockStack gap="400">
                                {haveInputField && (
                                    <InlineStack gap="200">
                                        <div style={{ flexGrow: 1 }}>
                                            <TextField
                                                role="combobox"
                                                label={t("time.since", {
                                                    ns: "translation",
                                                })}
                                                labelHidden
                                                // prefix={
                                                //     <Icon
                                                //         source={CalendarIcon}
                                                //     />
                                                // }
                                                value={inputValues.date_from}
                                                onChange={
                                                    handleStartInputValueChange
                                                }
                                                onBlur={handleInputBlur}
                                                autoComplete="off"
                                            />
                                        </div>
                                        {/* <Icon source={ArrowRightIcon} /> */}
                                        <div style={{ flexGrow: 1 }}>
                                            <TextField
                                                role="combobox"
                                                label={t("time.until", {
                                                    ns: "translation",
                                                })}
                                                labelHidden
                                                // prefix={
                                                //     <Icon
                                                //         source={CalendarIcon}
                                                //     />
                                                // }
                                                value={inputValues.date_to}
                                                onChange={
                                                    handleEndInputValueChange
                                                }
                                                onBlur={handleInputBlur}
                                                autoComplete="off"
                                            />
                                        </div>
                                    </InlineStack>
                                )}
                                <div>
                                    <DatePicker
                                        month={month}
                                        year={year}
                                        selected={{
                                            start: activeDateRange.period.since,
                                            end: activeDateRange.period.until,
                                        }}
                                        onMonthChange={handleMonthChange}
                                        onChange={handleCalendarChange}
                                        multiMonth={shouldShowMultiMonth}
                                        allowRange
                                    />
                                </div>
                            </BlockStack>
                        </Box>
                    </InlineGrid>
                </Popover.Pane>
                <Popover.Pane fixed>
                    <Popover.Section>
                        <InlineStack align="end" gap={400}>
                            <Button onClick={cancel}>
                                {t("cancel", { ns: "translation" })}
                            </Button>
                            <Button onClick={handleApplyDate} variant="primary">
                                {t("apply", { ns: "translation" })}
                            </Button>
                        </InlineStack>
                    </Popover.Section>
                </Popover.Pane>
            </Box>
        </Popover>
    );
};

export default DatePicking;